// src/pages/admin/BlogEdit.js
import React, { useState, useEffect } from "react";
import { Link, useParams, useNavigate } from "react-router-dom";
import axios from "axios";

const BlogEdit = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [openMaster, setOpenMaster] = useState(false);
  const [categories, setCategories] = useState([]);
  const [blogs, setBlogs] = useState([]);
  const [form, setForm] = useState({
    title: "",
    full_content: "",
    user_id: "",
    category_id: "",
  });
  const [imageFile, setImageFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch categories
  const fetchCategories = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categories");
      setCategories(res.data);
    } catch (err) {
      console.error("Failed to fetch categories", err);
    }
  };

  // Fetch blogs
  const fetchBlogs = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/blogs");
      setBlogs(res.data);
    } catch (err) {
      console.error("Failed to fetch blogs", err);
    }
  };

  // Fetch blog for editing
  const fetchBlog = async () => {
    try {
      const res = await axios.get(`http://localhost:5000/api/blogs/${id}`);
      setForm({
        title: res.data.title || "",
        full_content: res.data.full_content || "",
        user_id: res.data.user_id?.toString() || "",
        category_id: res.data.category_id?.toString() || "",
      });
    } catch (err) {
      console.error("Failed to fetch blog", err);
    }
  };

  useEffect(() => {
    fetchCategories();
    fetchBlogs();
    fetchBlog();
  }, [id]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    setImageFile(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const formData = new FormData();
      formData.append("title", form.title);
      formData.append("full_content", form.full_content);
      formData.append("user_id", Number(form.user_id));
      formData.append("category_id", Number(form.category_id));
      if (imageFile) {
        formData.append("image", imageFile);
      }

      await axios.put(`http://localhost:5000/api/blogs/${id}`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      navigate("/admin/blog-manage");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to update blog.");
    } finally {
      setLoading(false);
    }
  };

  const getCategoryName = (catId) => {
    const cat = categories.find((c) => c.id === catId);
    return cat ? cat.name : "Unknown";
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar (Same as AdminDashboard) */}
      <div className="w-64 bg-white border-r shadow fixed left-0 top-0 h-full z-10">
        <div className="px-6 py-4 border-b">
          <img src="/your-logo.png" alt="Logo" className="w-36" />
          <p className="text-sm text-gray-500">Blog Page</p>
        </div>

        <nav className="mt-4 px-4">
          <div
            onMouseEnter={() => setOpenMaster(true)}
            onMouseLeave={() => setOpenMaster(false)}
            className="relative cursor-pointer"
          >
            <p className="py-2 font-medium text-gray-800 hover:text-blue-600 flex justify-between items-center">
              Master <span>›</span>
            </p>
            {openMaster && (
              <div className="ml-4 space-y-2">
                <Link
                  to="/admin/category-manage"
                  className="block text-sm text-gray-600 hover:text-blue-600"
                >
                  ➤ Edit Category
                </Link>
                <Link
                  to="/admin/blog-manage"
                  className="block text-sm text-gray-600 hover:text-blue-600"
                >
                  ➤ Edit Blog
                </Link>
              </div>
            )}
          </div>
        </nav>
      </div>

      {/* Main content */}
      <main className="ml-64 flex-1 p-6">
        <div className="bg-white shadow rounded-lg p-6">
          <h1 className="text-2xl font-bold mb-6">Edit Blog</h1>

          {error && (
            <p className="mb-4 text-red-600 font-medium bg-red-100 p-3 rounded">
              {error}
            </p>
          )}

          {/* Edit Form */}
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">
                Title
              </label>
              <input
                type="text"
                name="title"
                value={form.title}
                onChange={handleChange}
                className="mt-1 block w-full border-gray-300 rounded-md shadow-sm"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">
                Full Content
              </label>
              <textarea
                name="full_content"
                value={form.full_content}
                onChange={handleChange}
                rows="6"
                className="mt-1 block w-full border-gray-300 rounded-md shadow-sm"
                required
              ></textarea>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">
                Upload Image
              </label>
              <input
                type="file"
                accept="image/*"
                onChange={handleFileChange}
                className="mt-1 block w-full"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">
                User ID
              </label>
              <input
                type="number"
                name="user_id"
                value={form.user_id}
                onChange={handleChange}
                className="mt-1 block w-full border-gray-300 rounded-md shadow-sm"
                required
                min={1}
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700">
                Category
              </label>
              <select
                name="category_id"
                value={form.category_id}
                onChange={handleChange}
                className="mt-1 block w-full border-gray-300 rounded-md shadow-sm"
                required
              >
                <option value="" disabled>
                  Select category
                </option>
                {categories.map((cat) => (
                  <option key={cat.id} value={cat.id}>
                    {cat.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <button
                type="submit"
                disabled={loading}
                className="bg-blue-600 text-white px-4 py-2 rounded shadow hover:bg-blue-700"
              >
                {loading ? "Updating..." : "Update Blog"}
              </button>
            </div>
          </form>
        </div>

        {/* Table of Blogs */}
        <div className="mt-10 bg-white shadow rounded-lg p-6">
          <h2 className="text-xl font-bold mb-4">All Blogs</h2>
          <div className="overflow-x-auto">
            <table className="min-w-full border border-gray-300 rounded-md">
              <thead className="bg-gray-100">
                <tr>
                  <th className="py-3 px-4 border-b text-left">ID</th>
                  <th className="py-3 px-4 border-b text-left">Title</th>
                  <th className="py-3 px-4 border-b text-left">Category</th>
                </tr>
              </thead>
              <tbody>
                {blogs.length === 0 && (
                  <tr>
                    <td
                      colSpan={3}
                      className="py-6 text-center text-gray-500"
                    >
                      No blogs found.
                    </td>
                  </tr>
                )}
                {blogs.map((blog) => (
                  <tr key={blog.id} className="hover:bg-gray-50">
                    <td className="py-2 px-4 border-b">{blog.id}</td>
                    <td className="py-2 px-4 border-b">{blog.title}</td>
                    <td className="py-2 px-4 border-b">
                      {getCategoryName(blog.category_id)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>
    </div>
  );
};

export default BlogEdit;
